#!/usr/bin/env python3
"""
scripts/download_tinystories.py

Download Microsoft / Ronen Eldan's TinyStories dataset (~2M short
synthetic children's stories generated by GPT-3.5/4) from the
HuggingFace hub and write it out as 10k-stories-per-file plain `.txt`
shards. The output is consumed by `./build/prepare_data` which tokenizes
the shards with the GPT-2 BPE and produces a memory-mappable `.npy`.

TinyStories is the default benchmark corpus in this repo because:
  * It's small (~500 MB tokenized) so it fits on any laptop.
  * Vocabulary is restricted, making 30M-parameter models genuinely
    fluent after only a few thousand training steps — useful for the
    chat-quality eval at the end of the benchmark suite.

Requires: `pip install datasets` (auto-installed if missing).

Usage:
    python3 scripts/download_tinystories.py
    python3 scripts/download_tinystories.py --max-stories 100000
    python3 scripts/download_tinystories.py --output-dir /tmp/ts

--- Reads ---
    HuggingFace `roneneldan/TinyStories` dataset (cached under
    ~/.cache/huggingface on first run).

--- Writes / Side effects ---
    <output_dir>/stories_0000.txt, stories_0001.txt, …
        Each file holds up to `batch_size` (10000) stories, separated
        by a blank line.
    May invoke `pip install datasets --quiet` if `datasets` is missing.

--- Calls ---
    datasets.load_dataset (HuggingFace)
    pip (only if `datasets` import fails)

--- Role in workflow ---
    Optional convenience wrapper around the HF datasets library. Most of
    the orchestration scripts (jetstream_run.sh, kzin_run.sh) skip this
    and call `prepare_data --download-hf roneneldan/TinyStories`
    directly, which bypasses the .txt staging step entirely.
"""
import argparse
import os
import sys


def main():
    """Parse args, download TinyStories, write to text shards."""
    parser = argparse.ArgumentParser()
    # 500k stories ≈ 200 MB tokenized — plenty for a 30M-param model.
    parser.add_argument("--max-stories", type=int, default=500000,
                        help="Max stories to download (default: 500k)")
    parser.add_argument("--output-dir", default="data/tinystories_raw",
                        help="Output directory for text files")
    args = parser.parse_args()

    # Lazily import `datasets` so users without it get a self-healing
    # script rather than a bare ImportError.
    try:
        from datasets import load_dataset
    except ImportError:
        print("Installing datasets library...")
        os.system(f"{sys.executable} -m pip install datasets --quiet")
        from datasets import load_dataset

    print(f"Downloading TinyStories (up to {args.max_stories} stories)...")
    # `datasets` will read from its on-disk cache on subsequent runs,
    # so re-running this script is essentially free after the first time.
    ds = load_dataset("roneneldan/TinyStories", split="train")

    os.makedirs(args.output_dir, exist_ok=True)

    # Shard the dataset into manageable text files. 10000 stories per
    # file keeps individual file sizes around 5–10 MB.
    batch_size = 10000
    total = min(len(ds), args.max_stories)
    file_idx = 0

    for start in range(0, total, batch_size):
        end = min(start + batch_size, total)
        # 4-digit zero-padded index keeps shards in lexicographic order.
        fpath = os.path.join(args.output_dir, f"stories_{file_idx:04d}.txt")
        with open(fpath, "w") as f:
            for i in range(start, end):
                # Strip whitespace and skip empty rows. The blank line
                # written after each story doubles as a document boundary
                # for downstream tokenizers.
                text = ds[i]["text"].strip()
                if text:
                    f.write(text + "\n\n")
        file_idx += 1
        # `\r` redraws the same terminal line for a tidy progress meter.
        print(f"\r  Saved {end}/{total} stories...", end="", flush=True)

    print(f"\nDone! {total} stories saved to {args.output_dir}/")
    print(f"Files: {file_idx} files")


if __name__ == "__main__":
    main()
